  ('pukao-1fb53453-moex-00228', 'pukao-1fb53453', 'pukao-1fb53453-moex-111-bacbaae8', 'sub-pukao-1fb53453-04', NULL, 'single_choice', '當自然失業率下降時，在其他條件不變下，長期均衡所得與長期均衡物價，產生下列何者變化？', '["兩者皆上升", "兩者皆下降", "前者上升；後者下降", "前者下降；後者上升"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:53+00:00", "source_pdf_sha1": "6721b804e372", "answer_pdf_sha1": "50392ab0c756", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "419", "s": "0911", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要與財政學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('pukao-1fb53453-moex-00229', 'pukao-1fb53453', 'pukao-1fb53453-moex-111-bacbaae8', 'sub-pukao-1fb53453-04', NULL, 'single_choice', '年終摸彩時，小芳願意以現金5,000元換取小珍摸彩所中的旅宿券5,000元，對小芳而言現金或旅宿券二 者沒有差別，小珍則是非常高興換得現金。由此可推測出：', '["小芳不喜歡現金，小珍則不喜歡旅宿券", "小芳至少會花5,000元去旅行住宿", "雙方的效用都因為這個交換而有所增加", "小芳是風險規避者，而小珍則是風險偏好者"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:53+00:00", "source_pdf_sha1": "6721b804e372", "answer_pdf_sha1": "50392ab0c756", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "419", "s": "0911", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要與財政學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('pukao-1fb53453-moex-00230', 'pukao-1fb53453', 'pukao-1fb53453-moex-111-bacbaae8', 'sub-pukao-1fb53453-04', NULL, 'single_choice', '假設一雙占市場有廠商A與B，皆計畫推出新產品。廠商可選擇的策略為推出高品質產品（H）或是低品 質產品（L），其策略與利潤之關係如下圖。假設在同時決策之下，下列敘述何者正確？ B廠 L H A廠 L （40，40） （10，80） H （80，10） （20，20） （表中數字左方為A廠之利潤、右方為B廠之利潤）', '["Nash均衡為（廠商A選擇H、廠商B選擇L）", "Nash均衡為（廠商A選擇L、廠商B選擇H）", "Nash均衡為（廠商A選擇H、廠商B選擇H）", "不存在Nash均衡"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:53+00:00", "source_pdf_sha1": "6721b804e372", "answer_pdf_sha1": "50392ab0c756", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "419", "s": "0911", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要與財政學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('pukao-1fb53453-moex-00231', 'pukao-1fb53453', 'pukao-1fb53453-moex-111-bacbaae8', 'sub-pukao-1fb53453-04', NULL, 'single_choice', '承上題，「若由B廠商先選擇品質，A廠商在看到B廠商的決定之後再選擇」時，請問下列敘述何者正確？', '["B廠商選擇高品質與低品質的機率各為0.5", "B廠商會選擇低品質", "B廠商會選擇高品質", "條件不足無法判斷"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:53+00:00", "source_pdf_sha1": "6721b804e372", "answer_pdf_sha1": "50392ab0c756", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "419", "s": "0911", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要與財政學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('pukao-1fb53453-moex-00232', 'pukao-1fb53453', 'pukao-1fb53453-moex-111-bacbaae8', 'sub-pukao-1fb53453-04', NULL, 'single_choice', '短期來說，當固定生產要素的價格上升時：', '["邊際成本線上移，平均成本線不變", "邊際成本線不變，平均成本線上移", "邊際成本線、平均成本線均不變", "邊際成本線、平均成本線均上移"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:53+00:00", "source_pdf_sha1": "6721b804e372", "answer_pdf_sha1": "50392ab0c756", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "419", "s": "0911", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要與財政學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財經廉政"}'::jsonb, NULL),
